  ('diplomatic-9e854390-moex-00191', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '有關結社自由之限制，依司法院大法官解釋，下列敘述何者錯誤？', '["結社自由保障人民團體成立時之命名權及嗣後之更名權", "內政部以行政命令規定「人民團體經主管機關限期整理者，其理監事之職權應即停止」，違反法律 保留原則", "基於國家安全理由，主張共產主義或分裂國土之結社，不受憲法上結社自由之保障", "人民團體法規定職業團體理事長應「由理事就常務理事中選舉之，不設常務理事者，就理事中互選 之」，違反比例原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00192', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依司法院大法官解釋意旨，關於職業自由之敘述，下列何者錯誤？', '["醫師法將醫師區分為醫師、中醫師及牙醫師，禁止不具有醫師資格之中醫師以「限醫師指示使用」 之西藥處方為人治病等規定，大法官認為尚屬合憲", "「航空人員體格檢查標準」禁止不合格之民航技師繼續執業之規定，大法官認為係屬對其選擇職業 自由之客觀條件限制，且已違反比例原則而違憲", "藥事法限制醫師藥品調劑權之規定，大法官認為並未牴觸憲法保障人民工作權及比例原則等規定意 旨，尚屬合憲", "道路交通管理處罰條例不問計程車駕駛人之犯行是否足以顯示對乘客安全具有實質風險，均吊扣其 執業登記證、廢止其執業登記之規定，大法官認為對駕駛人工作權之限制已違反比例原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "08ce77db5d69", "answer_pdf_sha1": "e245cea2e766", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
